﻿/**
 * @module followers
 * @description Follower tracker + following list sorted by following-count.
 * @see docs/modules/followers.md
 */
    /* ===================================================================== *
     *  FOLLOWERS â€” snapshot tracker + sort following by following-count     *
     * ===================================================================== */
    const Followers = {
        firstShow: true,
        running: false,
        stopFlag: false,
        // In-memory working set for the current sorted following scan
        rows: [],
        // Sort: 'following_desc' | 'following_asc' | 'followers_desc' | 'name'
        sortMode: Core.store.get('followersSort', 'following_desc'),
        enrichDelayMs: 900,

        onShow() {
            if (this.firstShow) {
                this.render();
                this.firstShow = false;
            }
            this.refreshSnapshotSummary();
            this.checkLocation();
        },

        render() {
            const pane = UI.el('tem-pane-followers');
            if (!pane) return;
            pane.innerHTML = `
              <div class="tem-warn-box">Walks your Following / Followers pages and looks up public profile stats. Stay on the list page while scanning. Respect rate limits â€” enrichment uses UserByScreenName (~1 req/account).</div>

              <div class="tem-section">
                <h4>Follower tracker (snapshots)</h4>
                <p>Save a snapshot of your <strong>Followers</strong> list, then compare later to see who followed or left. Data stays in this browser (<code>localStorage</code>).</p>
                <div class="tem-stats" id="tem-f-snap-stats">
                  <div class="tem-stat"><div class="tem-stat-v" id="tem-f-snap-count">â€“</div><div class="tem-stat-l">Last snapshot</div></div>
                  <div class="tem-stat"><div class="tem-stat-v" id="tem-f-snap-when">â€“</div><div class="tem-stat-l">Taken</div></div>
                  <div class="tem-stat"><div class="tem-stat-v" id="tem-f-hist-n">0</div><div class="tem-stat-l">History</div></div>
                </div>
                <div class="tem-btns">
                  <button class="tem-btn tem-btn-primary" id="tem-f-snap" type="button">Snapshot followers</button>
                  <button class="tem-btn tem-btn-ghost" id="tem-f-diff" type="button">Diff vs previous</button>
                </div>
                <div id="tem-f-diff-out" class="tem-note" style="margin-top:10px"></div>
              </div>

              <div class="tem-section">
                <h4>Following list â€” sort by following count</h4>
                <p>Scan accounts on your <strong>Following</strong> page, fetch each account's following count, and list them sorted. Does not unfollow anyone.</p>
                <label class="tem-label" for="tem-f-sort">Sort by</label>
                <select id="tem-f-sort" class="tem-input">
                  <option value="following_desc">Following count (high â†’ low)</option>
                  <option value="following_asc">Following count (low â†’ high)</option>
                  <option value="followers_desc">Followers count (high â†’ low)</option>
                  <option value="name">Handle (Aâ€“Z)</option>
                </select>
                <label class="tem-label" for="tem-f-max">Max accounts to enrich (0 = all scanned)</label>
                <input id="tem-f-max" type="number" class="tem-input" min="0" value="${Core.store.get('followersMax', 200)}">
                <div class="tem-btns">
                  <button class="tem-btn tem-btn-primary" id="tem-f-scan" type="button">Scan &amp; sort following</button>
                  <button class="tem-btn tem-btn-ghost" id="tem-f-stop" type="button" disabled>Stop</button>
                </div>
                <div class="tem-btns">
                  <button class="tem-btn tem-btn-ghost" id="tem-f-export" type="button" disabled>Export CSV</button>
                  <button class="tem-btn tem-btn-ghost" id="tem-f-export-json" type="button" disabled>Export JSON</button>
                </div>
                <div class="tem-status idle" id="tem-f-status">Idle</div>
                <div class="tem-now" id="tem-f-now" style="display:none"></div>
              </div>

              <div class="tem-section">
                <h4>Sorted results</h4>
                <div id="tem-f-list" class="tem-f-list"><p class="tem-note">Run a scan to populate this table.</p></div>
              </div>
              <div class="tem-foot">Follower tracker Â· v${Core.version}</div>`;

            UI.el('tem-f-sort').value = this.sortMode;
            UI.el('tem-f-sort').onchange = () => {
                this.sortMode = UI.el('tem-f-sort').value;
                Core.store.set('followersSort', this.sortMode);
                this.renderTable();
            };
            UI.el('tem-f-max').onchange = () => {
                Core.store.set('followersMax', parseInt(UI.el('tem-f-max').value, 10) || 0);
            };
            UI.el('tem-f-snap').onclick = () => this.snapshotFollowers();
            UI.el('tem-f-diff').onclick = () => this.diffSnapshots();
            UI.el('tem-f-scan').onclick = () => this.scanAndSortFollowing();
            UI.el('tem-f-stop').onclick = () => { this.stopFlag = true; };
            UI.el('tem-f-export').onclick = () => this.exportCsv();
            UI.el('tem-f-export-json').onclick = () => this.exportJson();
            this.refreshSnapshotSummary();
        },

        setStatus(kind, text) {
            const el = UI.el('tem-f-status');
            if (!el) return;
            el.className = 'tem-status ' + kind;
            el.textContent = text;
        },

        setNow(text) {
            const el = UI.el('tem-f-now');
            if (!el) return;
            if (!text) { el.style.display = 'none'; return; }
            el.style.display = 'block';
            el.textContent = text;
        },

        checkLocation() {
            const path = location.pathname.toLowerCase();
            const onFollowers = /\/followers\/?$/.test(path) || /\/verified_followers\/?$/.test(path);
            const onFollowing = /\/following\/?$/.test(path);
            if (!onFollowers && !onFollowing) {
                this.setNow('Tip: open your profile â†’ Followers (for snapshots) or Following (for sort scan).');
            }
        },

        // ---- Snapshot storage ------------------------------------------------

        _historyKey() { return 'followersHistory:' + (Core.username || 'me').toLowerCase(); },

        loadHistory() {
            return Core.store.get(this._historyKey(), []);
        },

        saveHistory(hist) {
            // Keep last 20 snapshots to avoid blowing localStorage
            Core.store.set(this._historyKey(), hist.slice(-20));
        },

        refreshSnapshotSummary() {
            const hist = this.loadHistory();
            const last = hist[hist.length - 1];
            const c = UI.el('tem-f-snap-count');
            const w = UI.el('tem-f-snap-when');
            const n = UI.el('tem-f-hist-n');
            if (n) n.textContent = String(hist.length);
            if (!last) {
                if (c) c.textContent = 'â€“';
                if (w) w.textContent = 'â€“';
                return;
            }
            if (c) c.textContent = String(last.handles?.length || 0);
            if (w) {
                try {
                    const d = new Date(last.at);
                    w.textContent = d.toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
                } catch (_) { w.textContent = 'â€“'; }
            }
        },

        /**
         * Walk the Followers list DOM (virtualized), collect unique handles.
         * Scrolls the page to load more rows until no growth or stop.
         */
        async collectListHandles(opts = {}) {
            const maxScrolls = opts.maxScrolls || 80;
            const settleMs = opts.settleMs || 700;
            const seen = new Map(); // handle -> { handle, name, mutual, private }
            let stagnant = 0;

            for (let i = 0; i < maxScrolls && !this.stopFlag; i++) {
                const cells = document.querySelectorAll('[data-testid="UserCell"]');
                let added = 0;
                for (const cell of cells) {
                    const handle = Follow.getUsername(cell);
                    if (!handle || handle === 'unknown') continue;
                    const key = handle.toLowerCase();
                    if (seen.has(key)) continue;
                    const nameEl = cell.querySelector('[dir="ltr"] span, a[role="link"] span');
                    seen.set(key, {
                        handle,
                        name: (nameEl && nameEl.textContent) || handle,
                        mutual: Follow.isMutual(cell),
                        private: Follow.isPrivate(cell)
                    });
                    added++;
                }
                this.setNow(`Scanned ${seen.size} unique accountsâ€¦ (scroll ${i + 1}/${maxScrolls})`);
                if (added === 0) {
                    stagnant++;
                    if (stagnant >= 3) break;
                } else {
                    stagnant = 0;
                }
                // Scroll the main timeline column
                const scroller = document.querySelector('[data-testid="primaryColumn"]') || document.scrollingElement || document.documentElement;
                const before = window.scrollY || scroller.scrollTop || 0;
                window.scrollBy(0, Math.min(window.innerHeight * 0.85, 900));
                await Core.sleep(settleMs);
                const after = window.scrollY || scroller.scrollTop || 0;
                if (Math.abs(after - before) < 4 && added === 0) {
                    stagnant++;
                    if (stagnant >= 3) break;
                }
            }
            return [...seen.values()];
        },

        async snapshotFollowers() {
            if (this.running) return;
            const path = location.pathname.toLowerCase();
            if (!/\/followers\/?$/.test(path) && !/\/verified_followers\/?$/.test(path)) {
                this.setStatus('pause', 'Open your Followers page first');
                alert('Go to your profile â†’ Followers, then run Snapshot again.');
                return;
            }
            this.running = true;
            this.stopFlag = false;
            this._setBusy(true);
            this.setStatus('run', 'Snapshotting followersâ€¦');
            try {
                const accounts = await this.collectListHandles({ maxScrolls: 120 });
                const handles = accounts.map(a => a.handle.toLowerCase()).sort();
                const snap = {
                    at: new Date().toISOString(),
                    username: Core.username || null,
                    handles,
                    meta: accounts
                };
                const hist = this.loadHistory();
                hist.push(snap);
                this.saveHistory(hist);
                this.refreshSnapshotSummary();
                this.setStatus('idle', `Saved ${handles.length} followers`);
                this.setNow(`Snapshot saved (${handles.length} handles). Use Diff vs previous to compare.`);
                console.log('[TEM Followers] Snapshot', snap);
            } catch (e) {
                console.error(e);
                this.setStatus('stop', 'Snapshot failed');
            } finally {
                this.running = false;
                this._setBusy(false);
            }
        },

        diffSnapshots() {
            const hist = this.loadHistory();
            const out = UI.el('tem-f-diff-out');
            if (!out) return;
            if (hist.length < 2) {
                out.innerHTML = 'Need at least <strong>two</strong> snapshots to diff. Take another later.';
                return;
            }
            const prev = hist[hist.length - 2];
            const curr = hist[hist.length - 1];
            const a = new Set(prev.handles || []);
            const b = new Set(curr.handles || []);
            const gained = [...b].filter(h => !a.has(h));
            const lost = [...a].filter(h => !b.has(h));
            out.innerHTML = `
              <strong>Diff</strong> ${Core.escapeHtml(prev.at?.slice(0, 10) || '?')} â†’ ${Core.escapeHtml(curr.at?.slice(0, 10) || '?')}<br>
              <span style="color:var(--ok)">+${gained.length} new</span> Â·
              <span style="color:var(--danger)">âˆ’${lost.length} lost</span>
              <div style="margin-top:8px;max-height:160px;overflow:auto;font-size:12px">
                ${gained.length ? '<div><strong>New:</strong> ' + gained.map(h => '@' + Core.escapeHtml(h)).join(', ') + '</div>' : ''}
                ${lost.length ? '<div style="margin-top:6px"><strong>Lost:</strong> ' + lost.map(h => '@' + Core.escapeHtml(h)).join(', ') + '</div>' : ''}
                ${!gained.length && !lost.length ? '<div>No changes between last two snapshots.</div>' : ''}
              </div>`;
            console.table({ gained: gained.length, lost: lost.length });
            if (gained.length) console.log('[TEM] New followers', gained);
            if (lost.length) console.log('[TEM] Lost followers', lost);
        },

        // ---- Sort following by following count -------------------------------

        async scanAndSortFollowing() {
            if (this.running) return;
            const path = location.pathname.toLowerCase();
            if (!/\/following\/?$/.test(path)) {
                this.setStatus('pause', 'Open your Following page first');
                alert('Go to your profile â†’ Following, then run Scan & sort again.');
                return;
            }
            this.running = true;
            this.stopFlag = false;
            this.rows = [];
            this._setBusy(true);
            this.setStatus('run', 'Scanning Following listâ€¦');
            try {
                const accounts = await this.collectListHandles({ maxScrolls: 100 });
                if (this.stopFlag) {
                    this.setStatus('stop', 'Stopped');
                    return;
                }
                const max = parseInt(UI.el('tem-f-max')?.value, 10);
                const toEnrich = (!max || max <= 0) ? accounts : accounts.slice(0, max);
                this.setStatus('run', `Enriching ${toEnrich.length} profilesâ€¦`);

                for (let i = 0; i < toEnrich.length && !this.stopFlag; i++) {
                    const acc = toEnrich[i];
                    this.setNow(`Looking up @${acc.handle} (${i + 1}/${toEnrich.length})`);
                    const profile = await Core.fetchUserByScreenName(acc.handle);
                    this.rows.push({
                        handle: acc.handle,
                        name: profile?.name || acc.name,
                        following: profile?.following ?? null,
                        followers: profile?.followers ?? null,
                        location: profile?.location || '',
                        mutual: acc.mutual,
                        private: acc.private,
                        enriched: !!profile
                    });
                    this.renderTable();
                    await Core.sleep(this.enrichDelayMs + Core.rand(0, 400));
                }

                // Include non-enriched remainder with null counts
                if (!max || max <= 0 || max >= accounts.length) {
                    /* all attempted */
                } else {
                    for (const acc of accounts.slice(max)) {
                        this.rows.push({
                            handle: acc.handle, name: acc.name,
                            following: null, followers: null, location: '',
                            mutual: acc.mutual, private: acc.private, enriched: false
                        });
                    }
                }

                this.renderTable();
                const ok = this.rows.filter(r => r.enriched).length;
                this.setStatus(this.stopFlag ? 'stop' : 'idle',
                    this.stopFlag ? `Stopped (${ok} enriched)` : `Done â€” ${ok} enriched, ${this.rows.length} total`);
                this.setNow(`Sorted by: ${this.sortMode}. Export if needed.`);
                UI.el('tem-f-export').disabled = this.rows.length === 0;
                UI.el('tem-f-export-json').disabled = this.rows.length === 0;
            } catch (e) {
                console.error(e);
                this.setStatus('stop', 'Scan failed');
            } finally {
                this.running = false;
                this._setBusy(false);
            }
        },

        sortRows() {
            const mode = this.sortMode || 'following_desc';
            const copy = this.rows.slice();
            if (mode === 'name') {
                copy.sort((a, b) => String(a.handle).localeCompare(String(b.handle)));
                return copy;
            }
            const key = mode.includes('followers') ? 'followers' : 'following';
            const asc = mode.endsWith('_asc');
            copy.sort((a, b) => {
                const av = a[key], bv = b[key];
                if (av == null && bv == null) return String(a.handle).localeCompare(String(b.handle));
                if (av == null) return 1; // nulls last
                if (bv == null) return -1;
                return asc ? av - bv : bv - av;
            });
            return copy;
        },

        renderTable() {
            const host = UI.el('tem-f-list');
            if (!host) return;
            if (!this.rows.length) {
                host.innerHTML = '<p class="tem-note">Run a scan to populate this table.</p>';
                return;
            }
            const sorted = this.sortRows();

            const rowsHtml = sorted.map((r, i) => `
              <tr>
                <td class="tem-f-rank">${i + 1}</td>
                <td><a href="/${Core.escapeHtml(r.handle)}" target="_blank" rel="noopener">@${Core.escapeHtml(r.handle)}</a>
                  ${r.mutual ? '<span class="tem-f-tag">mutual</span>' : ''}
                  ${r.private ? '<span class="tem-f-tag">private</span>' : ''}
                </td>
                <td class="tem-f-num">${r.following != null ? r.following.toLocaleString() : 'â€”'}</td>
                <td class="tem-f-num">${r.followers != null ? r.followers.toLocaleString() : 'â€”'}</td>
                <td class="tem-f-loc">${Core.escapeHtml(r.location || 'â€”')}</td>
              </tr>`).join('');

            host.innerHTML = `
              <table class="tem-f-table">
                <thead>
                  <tr>
                    <th>#</th><th>Handle</th>
                    <th title="How many accounts they follow">Following</th>
                    <th>Followers</th><th>Location</th>
                  </tr>
                </thead>
                <tbody>${rowsHtml}</tbody>
              </table>`;
        },

        exportCsv() {
            const sorted = this._exportRows();
            if (!sorted.length) return;
            const header = 'rank,handle,name,following,followers,location,mutual,private,enriched';
            const lines = sorted.map((r, i) => [
                i + 1,
                r.handle,
                JSON.stringify(r.name || ''),
                r.following ?? '',
                r.followers ?? '',
                JSON.stringify(r.location || ''),
                r.mutual ? 1 : 0,
                r.private ? 1 : 0,
                r.enriched ? 1 : 0
            ].join(','));
            this._download('tem-following-sorted.csv', [header, ...lines].join('\n'), 'text/csv');
        },

        exportJson() {
            const sorted = this._exportRows();
            if (!sorted.length) return;
            this._download(
                'tem-following-sorted.json',
                JSON.stringify({ at: new Date().toISOString(), sort: this.sortMode, rows: sorted }, null, 2),
                'application/json'
            );
        },

        _exportRows() {
            return this.sortRows();
        },

        _download(filename, text, mime) {
            const blob = new Blob([text], { type: mime });
            const a = document.createElement('a');
            a.href = URL.createObjectURL(blob);
            a.download = filename;
            a.click();
            setTimeout(() => URL.revokeObjectURL(a.href), 2000);
        },

        _setBusy(busy) {
            const scan = UI.el('tem-f-scan');
            const stop = UI.el('tem-f-stop');
            const snap = UI.el('tem-f-snap');
            if (scan) scan.disabled = busy;
            if (snap) snap.disabled = busy;
            if (stop) stop.disabled = !busy;
        }
    };

/* ---- src/modules/geoguard.js ---- */
/**
 * @module geoguard
 * @description Timeline watcher: soft region hide + optional auto-block (self-reported location).
 * @see docs/modules/geoguard.md
 */
    const GeoGuard = {
        firstShow: true,
        watching: false,
        observer: null,
        queue: [],
        processing: false,
        seen: new Set(),            // handles already evaluated this session
        matchedHandles: new Set(),  // lowercased handles that matched region
        blockedThisSession: 0,
        matchedThisSession: 0,
        hiddenThisSession: 0,
        scannedThisSession: 0,
        logLines: [],
        profileCache: {},           // handle -> profile + match meta
        delayMs: 1100,
        _scanScheduled: false,

        // Default South Asia / India location needles (case-insensitive substring).
        // Editable in the UI; stored in localStorage.
        defaultNeedles: [
            // India
            'india', 'bharat', 'hindustan', 'mumbai', 'delhi', 'new delhi', 'bangalore', 'bengaluru',
            'hyderabad', 'chennai', 'kolkata', 'calcutta', 'pune', 'ahmedabad', 'jaipur', 'lucknow',
            'kanpur', 'nagpur', 'indore', 'bhopal', 'patna', 'ranchi', 'surat', 'vadodara',
            'kochi', 'cochin', 'trivandrum', 'thiruvananthapuram', 'mysore', 'mysuru', 'gurgaon',
            'gurugram', 'noida', 'ghaziabad', 'faridabad', 'chandigarh', 'amritsar', 'ludhiana',
            'varanasi', 'agra', 'goa', 'kerala', 'tamil nadu', 'karnataka', 'maharashtra',
            'gujarat', 'rajasthan', 'punjab, india', 'west bengal', 'uttar pradesh', 'bihar',
            'odisha', 'orissa', 'telangana', 'andhra', 'assam', 'jharkhand', 'chhattisgarh',
            'madhya pradesh', 'haryana', 'uttarakhand', 'himachal', 'jammu', 'kashmir',
            '🇮🇳', 'in 🇮🇳',
            // Broader South Asia
            'pakistan', 'karachi', 'lahore', 'islamabad', 'rawalpindi', 'peshawar', 'multan',
            'bangladesh', 'dhaka', 'chittagong', 'chattogram',
            'sri lanka', 'colombo', 'kandy',
            'nepal', 'kathmandu',
            'bhutan', 'thimphu',
            'maldives', 'male, maldives',
            'afghanistan', 'kabul',
            'south asia', 'southasian', 'desi'
        ],

        onShow() {
            if (this.firstShow) {
                this.render();
                this.firstShow = false;
            }
            this.refreshStats();
        },

        render() {
            const pane = UI.el('tem-pane-geoguard');
            if (!pane) return;

            const needles = Core.store.get('geoNeedles', this.defaultNeedles).join('\n');
            const whitelist = (Core.store.get('geoWhitelist', []) || []).join('\n');
            const dryRun = Core.store.get('geoDryRun', true);
            const softHide = Core.store.get('geoSoftHide', true);
            const autoStart = Core.store.get('geoAutoStart', false);
            const useBio = Core.store.get('geoUseBio', false);

            pane.innerHTML = `
              <div class="tem-warn-box">
                Matches <strong>self-reported</strong> profile location (and optional bio) text only —
                not IP, passport, or ethnicity. Expect false positives/negatives.
                Prefer <strong>soft hide</strong> (client-side) over live block (ToS risk).
              </div>

              <div class="tem-section">
                <h4>Timeline Geo Guard</h4>
                <p>Looks up authors on the timeline. Matching accounts can be <strong>soft-hidden</strong> (DOM only) and/or blocked.</p>
                <div class="tem-stats" style="grid-template-columns:repeat(4,1fr)">
                  <div class="tem-stat"><div class="tem-stat-v" id="tem-g-scanned">0</div><div class="tem-stat-l">Scanned</div></div>
                  <div class="tem-stat"><div class="tem-stat-v" id="tem-g-matched">0</div><div class="tem-stat-l">Matched</div></div>
                  <div class="tem-stat"><div class="tem-stat-v" id="tem-g-hidden">0</div><div class="tem-stat-l">Hidden</div></div>
                  <div class="tem-stat"><div class="tem-stat-v" id="tem-g-blocked">0</div><div class="tem-stat-l">Blocked</div></div>
                </div>
                <label class="tem-check"><input type="checkbox" id="tem-g-soft" ${softHide ? 'checked' : ''}> <strong>Soft hide</strong> matching posts (recommended; reversible in-session)</label>
                <label class="tem-check"><input type="checkbox" id="tem-g-dry" ${dryRun ? 'checked' : ''}> Do not live-block (log only for block path)</label>
                <label class="tem-check"><input type="checkbox" id="tem-g-bio" ${useBio ? 'checked' : ''}> Also match bio / description text</label>
                <label class="tem-check"><input type="checkbox" id="tem-g-autostart" ${autoStart ? 'checked' : ''}> Auto-start watch when script loads</label>
                <div class="tem-btns">
                  <button class="tem-btn tem-btn-primary" id="tem-g-start" type="button">Start watching timeline</button>
                  <button class="tem-btn tem-btn-ghost" id="tem-g-stop" type="button" disabled>Stop</button>
                </div>
                <div class="tem-btns">
                  <button class="tem-btn tem-btn-ghost" id="tem-g-unhide" type="button">Unhide soft-hidden posts</button>
                </div>
                <div class="tem-status idle" id="tem-g-status">Idle</div>
                <div class="tem-now" id="tem-g-now" style="display:none"></div>
              </div>

              <div class="tem-section">
                <h4>Region needles (one per line)</h4>
                <p>Case-insensitive substrings tested against profile location${useBio ? ' and bio' : ''}.</p>
                <textarea id="tem-g-needles" class="tem-input" rows="8">${Core.escapeHtml(needles)}</textarea>
                <div class="tem-btns">
                  <button class="tem-btn tem-btn-ghost" id="tem-g-save-needles" type="button">Save needles</button>
                  <button class="tem-btn tem-btn-ghost" id="tem-g-reset-needles" type="button">Reset defaults</button>
                </div>
              </div>

              <div class="tem-section">
                <h4>Whitelist (never hide / block)</h4>
                <textarea id="tem-g-whitelist" class="tem-input" rows="3" placeholder="@friend&#10;@org">${Core.escapeHtml(whitelist)}</textarea>
                <div class="tem-btns">
                  <button class="tem-btn tem-btn-ghost" id="tem-g-save-wl" type="button">Save whitelist</button>
                </div>
              </div>

              <div class="tem-section">
                <h4>Session log</h4>
                <div class="tem-log" id="tem-g-log"></div>
                <div class="tem-btns">
                  <button class="tem-btn tem-btn-ghost" id="tem-g-export" type="button">Export log JSON</button>
                  <button class="tem-btn tem-btn-ghost" id="tem-g-clear" type="button">Clear session</button>
                </div>
              </div>
              <div class="tem-foot">Geo Guard · v${Core.version}</div>`;

            UI.el('tem-g-start').onclick = () => this.startWatch();
            UI.el('tem-g-stop').onclick = () => this.stopWatch();
            UI.el('tem-g-soft').onchange = () => Core.store.set('geoSoftHide', UI.el('tem-g-soft').checked);
            UI.el('tem-g-dry').onchange = () => Core.store.set('geoDryRun', UI.el('tem-g-dry').checked);
            UI.el('tem-g-bio').onchange = () => Core.store.set('geoUseBio', UI.el('tem-g-bio').checked);
            UI.el('tem-g-autostart').onchange = () => Core.store.set('geoAutoStart', UI.el('tem-g-autostart').checked);
            UI.el('tem-g-unhide').onclick = () => this.unhideAll();
            UI.el('tem-g-save-needles').onclick = () => {
                const list = this._parseLines(UI.el('tem-g-needles').value);
                Core.store.set('geoNeedles', list);
                this.log('Saved ' + list.length + ' needles');
            };
            UI.el('tem-g-reset-needles').onclick = () => {
                Core.store.set('geoNeedles', this.defaultNeedles);
                UI.el('tem-g-needles').value = this.defaultNeedles.join('\n');
                this.log('Needles reset to defaults');
            };
            UI.el('tem-g-save-wl').onclick = () => {
                const list = this._parseLines(UI.el('tem-g-whitelist').value).map(h => h.replace(/^@/, '').toLowerCase());
                Core.store.set('geoWhitelist', list);
                this.log('Whitelist saved (' + list.length + ')');
            };
            UI.el('tem-g-export').onclick = () => this.exportLog();
            UI.el('tem-g-clear').onclick = () => {
                this.seen.clear();
                this.matchedHandles.clear();
                this.logLines = [];
                this.blockedThisSession = 0;
                this.matchedThisSession = 0;
                this.hiddenThisSession = 0;
                this.scannedThisSession = 0;
                this.refreshStats();
                this._paintLog();
            };
            this.refreshStats();
            this._paintLog();
            if (this.watching) this._setWatchUi(true);
        },

        _parseLines(text) {
            return String(text || '').split(/\r?\n/).map(s => s.trim()).filter(Boolean);
        },

        setStatus(kind, text) {
            const el = UI.el('tem-g-status');
            if (!el) return;
            el.className = 'tem-status ' + kind;
            el.textContent = text;
        },

        setNow(text) {
            const el = UI.el('tem-g-now');
            if (!el) return;
            if (!text) { el.style.display = 'none'; return; }
            el.style.display = 'block';
            el.textContent = text;
        },

        refreshStats() {
            const s = UI.el('tem-g-scanned');
            const m = UI.el('tem-g-matched');
            const h = UI.el('tem-g-hidden');
            const b = UI.el('tem-g-blocked');
            if (s) s.textContent = String(this.scannedThisSession);
            if (m) m.textContent = String(this.matchedThisSession);
            if (h) h.textContent = String(this.hiddenThisSession);
            if (b) b.textContent = String(this.blockedThisSession);
        },

        log(msg, data) {
            const line = { at: new Date().toISOString(), msg, ...(data || {}) };
            this.logLines.push(line);
            if (this.logLines.length > 500) this.logLines.shift();
            console.log('[TEM GeoGuard]', msg, data || '');
            this._paintLog();
        },

        _paintLog() {
            const el = UI.el('tem-g-log');
            if (!el) return;
            const recent = this.logLines.slice(-80).reverse();
            el.innerHTML = recent.map(l =>
                `<div>${Core.escapeHtml(l.at.slice(11, 19))} ${Core.escapeHtml(l.msg)}${l.handle ? ' @' + Core.escapeHtml(l.handle) : ''}${l.reason ? ' — ' + Core.escapeHtml(l.reason) : ''}</div>`
            ).join('') || '<div class="tem-note">No events yet.</div>';
        },

        startWatch() {
            if (this.watching) return;
            this.watching = true;
            this._setWatchUi(true);
            const soft = Core.store.get('geoSoftHide', true);
            const dry = Core.store.get('geoDryRun', true);
            this.setStatus('run', 'Watching timeline…');
            this.log('Watch started' +
                (soft ? ' · soft-hide ON' : ' · soft-hide OFF') +
                (dry ? ' · no live-block' : ' · LIVE BLOCK'));

            this.scanDom();

            this.observer = new MutationObserver(() => {
                if (!this.watching) return;
                this.scheduleScan();
            });
            try {
                this.observer.observe(document.body || document.documentElement, {
                    childList: true, subtree: true
                });
            } catch (e) {
                console.warn('[TEM GeoGuard] observer failed', e);
            }
            this._pump();
        },

        stopWatch() {
            this.watching = false;
            if (this.observer) {
                try { this.observer.disconnect(); } catch (_) { }
                this.observer = null;
            }
            this._setWatchUi(false);
            this.setStatus('idle', 'Stopped');
            this.setNow('');
            this.log('Watch stopped');
        },

        scheduleScan() {
            if (this._scanScheduled) return;
            this._scanScheduled = true;
            const run = () => {
                this._scanScheduled = false;
                if (this.watching) this.scanDom();
            };
            if (typeof requestAnimationFrame === 'function') requestAnimationFrame(run);
            else setTimeout(run, 50);
        },

        _setWatchUi(on) {
            const start = UI.el('tem-g-start');
            const stop = UI.el('tem-g-stop');
            if (start) start.disabled = on;
            if (stop) stop.disabled = !on;
        },

        /**
         * Author handle from a tweet article (primary User-Name link).
         */
        authorFromArticle(article) {
            const nameBlock = article.querySelector('[data-testid="User-Name"]');
            if (!nameBlock) return null;
            const links = nameBlock.querySelectorAll('a[href^="/"]');
            for (let i = 0; i < links.length; i++) {
                const href = links[i].getAttribute('href') || '';
                const m = href.match(/^\/([A-Za-z0-9_]{1,15})(?:\/|$|\?)/);
                if (m && !/^(home|explore|search|i|settings|messages|notifications|compose)$/i.test(m[1])) {
                    return m[1];
                }
            }
            return null;
        },

        /**
         * Soft-hide: hide the cell wrapper when possible so virtualized list gaps collapse better.
         */
        hideArticle(article, handle, reason) {
            if (!article || article.getAttribute('data-tem-geo-hidden') === '1') return false;
            const target = article.closest('[data-testid="cellInnerDiv"]') || article;
            target.setAttribute('data-tem-geo-hidden', '1');
            if (handle) target.setAttribute('data-tem-geo-handle', handle);
            if (reason) target.setAttribute('data-tem-geo-reason', reason);
            target.style.setProperty('display', 'none', 'important');
            this.hiddenThisSession++;
            return true;
        },

        hideArticlesForHandle(handle, reason) {
            if (!Core.store.get('geoSoftHide', true)) return 0;
            const key = String(handle || '').toLowerCase();
            let n = 0;
            const articles = document.querySelectorAll('article[data-testid="tweet"]');
            for (let i = 0; i < articles.length; i++) {
                const a = articles[i];
                const h = this.authorFromArticle(a);
                if (!h || h.toLowerCase() !== key) continue;
                if (this.hideArticle(a, h, reason)) n++;
            }
            if (n) this.refreshStats();
            return n;
        },

        unhideAll() {
            const nodes = document.querySelectorAll('[data-tem-geo-hidden="1"]');
            for (let i = 0; i < nodes.length; i++) {
                const el = nodes[i];
                el.removeAttribute('data-tem-geo-hidden');
                el.removeAttribute('data-tem-geo-handle');
                el.removeAttribute('data-tem-geo-reason');
                el.style.removeProperty('display');
            }
            this.log('Unhid ' + nodes.length + ' soft-hidden node(s)');
            this.setNow('Unhid ' + nodes.length + ' post(s). Matched handles stay cached until Clear session.');
        },

        /**
         * Extract author handles from visible tweets / UserCells; re-apply soft hides.
         */
        scanDom() {
            const handles = new Set();
            const soft = Core.store.get('geoSoftHide', true);

            const articles = document.querySelectorAll('article[data-testid="tweet"]');
            for (let i = 0; i < articles.length; i++) {
                const article = articles[i];
                const h = this.authorFromArticle(article);
                if (!h) continue;
                const key = h.toLowerCase();
                if (soft && this.matchedHandles.has(key)) {
                    this.hideArticle(article, h, 'cached match');
                }
                handles.add(h);
            }

            // Who-to-follow / sidebar cells
            document.querySelectorAll('[data-testid="UserCell"]').forEach(cell => {
                const h = Follow.getUsername(cell);
                if (h && h !== 'unknown') handles.add(h);
            });

            for (const h of handles) {
                const key = h.toLowerCase();
                if (this.seen.has(key)) continue;
                if (Core.username && key === Core.username.toLowerCase()) continue;
                this.seen.add(key);
                this.queue.push(h);
            }
            this.refreshStats();
        },

        async _pump() {
            if (this.processing) return;
            this.processing = true;
            try {
                while (this.watching) {
                    if (!this.queue.length) {
                        await Core.sleep(400);
                        continue;
                    }
                    const handle = this.queue.shift();
                    await this.evaluateHandle(handle);
                    await Core.sleep(this.delayMs + Core.rand(0, 350));
                }
            } finally {
                this.processing = false;
            }
        },

        matchRegion(profile) {
            const needles = Core.store.get('geoNeedles', this.defaultNeedles).map(n => String(n).toLowerCase());
            const useBio = Core.store.get('geoUseBio', false);
            const location = (profile.location || '').toLowerCase();
            const bio = useBio ? (profile.description || '').toLowerCase() : '';
            const hay = location + (useBio ? '\n' + bio : '');

            for (const n of needles) {
                if (!n) continue;
                if (hay.includes(n.toLowerCase())) {
                    return { match: true, reason: `needle "${n}" in ${location.includes(n.toLowerCase()) ? 'location' : 'bio'}` };
                }
            }

            // Optional script signal: Devanagari in location (common for India/Nepal)
            if (/[\u0900-\u097F]/.test(profile.location || '')) {
                return { match: true, reason: 'Devanagari script in location' };
            }
            return { match: false, reason: null };
        },

        async evaluateHandle(handle) {
            const key = handle.toLowerCase();
            const wl = new Set((Core.store.get('geoWhitelist', []) || []).map(h => String(h).replace(/^@/, '').toLowerCase()));
            if (wl.has(key)) {
                this.log('Skip whitelist', { handle });
                return;
            }

            this.setNow('Checking @' + handle);
            let profile = this.profileCache[key];
            if (!profile) {
                const fetched = await Core.fetchUserByScreenName(handle);
                if (!fetched) {
                    this.log('Lookup failed', { handle });
                    return;
                }
                profile = fetched;
                this.profileCache[key] = profile;
            }

            this.scannedThisSession++;
            this.refreshStats();

            const { match, reason } = this.matchRegion(profile);
            if (!match) {
                this.setNow('@' + handle + ' — no match (' + (profile.location || 'empty loc') + ')');
                return;
            }

            this.matchedThisSession++;
            this.matchedHandles.add(key);
            this.refreshStats();
            this.log('MATCH', { handle, reason, location: profile.location });

            // Soft hide: client-side only (works even when live-block is disabled)
            if (Core.store.get('geoSoftHide', true)) {
                const n = this.hideArticlesForHandle(handle, reason);
                this.setNow('Soft-hid @' + handle + (n ? ' (' + n + ' post(s))' : '') + ' — ' + reason);
                this.log('SOFT-HIDE', { handle, reason, posts: n });
            }

            const dry = Core.store.get('geoDryRun', true);
            if (dry) {
                if (!Core.store.get('geoSoftHide', true)) {
                    this.setNow('Match @' + handle + ' (no hide, no block) — ' + reason);
                }
                return;
            }

            this.setNow('Blocking @' + handle + '…');
            const ok = await Core.blockUser(profile.id || handle);
            if (ok) {
                this.blockedThisSession++;
                this.refreshStats();
                this.log('BLOCKED', { handle, reason, location: profile.location });
                const hist = Core.store.get('geoBlockHistory', []);
                hist.push({ at: new Date().toISOString(), handle, reason, location: profile.location });
                Core.store.set('geoBlockHistory', hist.slice(-1000));
            } else {
                this.log('Block failed', { handle });
            }
        },

        exportLog() {
            const payload = {
                at: new Date().toISOString(),
                scanned: this.scannedThisSession,
                matched: this.matchedThisSession,
                hidden: this.hiddenThisSession,
                blocked: this.blockedThisSession,
                matchedHandles: [...this.matchedHandles],
                lines: this.logLines,
                history: Core.store.get('geoBlockHistory', [])
            };
            const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
            const a = document.createElement('a');
            a.href = URL.createObjectURL(blob);
            a.download = 'tem-geoguard-log.json';
            a.click();
            setTimeout(() => URL.revokeObjectURL(a.href), 2000);
        }
    };

/* ---- src/modules/notifmute.js ---- */
/**
 * @module notifmute
 * @description Hide “liked your post” (and similar) rows on X notifications.
 * @see docs/modules/notifmute.md
 */
    const NotifMute = {
        firstShow: true,
        watching: false,
        observer: null,
        hiddenThisSession: 0,
        _scanScheduled: false,

        // English + a few common UI strings. Case-insensitive; tested against
        // cell textContent. Extend via localStorage tem:likeMutePatterns.
        defaultPatterns: [
            'liked your post',
            'liked your posts',
            'liked your reply',
            'liked your repost',
            'liked your retweet',
            'liked your quote',
            'liked a post you',
            'liked a reply you',
            'liked posts you were mentioned in',
            'liked a photo you',
            'liked a video you',
            // Grouped / alternate copy
            'others liked your',
            'other liked your',
            // Non-English fragments (optional coverage)
            'gefällt dein',           // de
            'a aimé votre',          // fr
            'le gustó tu',           // es
            'curtiu seu',            // pt
            'いいねしました'          // ja “liked”
        ],

        onShow() {
            if (this.firstShow) {
                this.render();
                this.firstShow = false;
            }
            this.refreshStats();
            this._setWatchUi(this.watching);
        },

        render() {
            const pane = UI.el('tem-pane-notifs');
            if (!pane) return;

            const enabled = Core.store.get('likeMuteEnabled', true);
            const autoStart = Core.store.get('likeMuteAutoStart', true);
            const patterns = (Core.store.get('likeMutePatterns', this.defaultPatterns) || this.defaultPatterns).join('\n');

            pane.innerHTML = `
              <div class="tem-warn-box">
                Client-side only: hides notification <em>rows in the DOM</em> that look like
                “liked your post”. Does not change X notification settings on the server.
                Selectors can break when X redesigns the page.
              </div>

              <div class="tem-section">
                <h4>Mute like notifications</h4>
                <p>On <code>/notifications</code>, collapse rows about likes so replies and follows stay visible.</p>
                <div class="tem-stats">
                  <div class="tem-stat"><div class="tem-stat-v" id="tem-n-hidden">0</div><div class="tem-stat-l">Hidden (session)</div></div>
                  <div class="tem-stat"><div class="tem-stat-v" id="tem-n-state">Off</div><div class="tem-stat-l">Watcher</div></div>
                  <div class="tem-stat"><div class="tem-stat-v" id="tem-n-path">–</div><div class="tem-stat-l">Path</div></div>
                </div>
                <label class="tem-check"><input type="checkbox" id="tem-n-enabled" ${enabled ? 'checked' : ''}> Enable like-mute when watching</label>
                <label class="tem-check"><input type="checkbox" id="tem-n-autostart" ${autoStart ? 'checked' : ''}> Auto-start watcher when script loads</label>
                <div class="tem-btns">
                  <button class="tem-btn tem-btn-primary" id="tem-n-start" type="button">Start watcher</button>
                  <button class="tem-btn tem-btn-ghost" id="tem-n-stop" type="button" disabled>Stop</button>
                </div>
                <div class="tem-btns">
                  <button class="tem-btn tem-btn-ghost" id="tem-n-scan" type="button">Scan once now</button>
                  <button class="tem-btn tem-btn-ghost" id="tem-n-unhide" type="button">Unhide (this page)</button>
                </div>
                <div class="tem-status idle" id="tem-n-status">Idle</div>
                <p class="tem-note">Tip: open Notifications (All or Verified) then start the watcher. Works best on the All tab.</p>
              </div>

              <div class="tem-section">
                <h4>Match patterns (one per line)</h4>
                <p>Case-insensitive substrings against each notification cell’s text.</p>
                <textarea id="tem-n-patterns" class="tem-input" rows="8">${Core.escapeHtml(patterns)}</textarea>
                <div class="tem-btns">
                  <button class="tem-btn tem-btn-ghost" id="tem-n-save" type="button">Save patterns</button>
                  <button class="tem-btn tem-btn-ghost" id="tem-n-reset" type="button">Reset defaults</button>
                </div>
              </div>
              <div class="tem-foot">Notif mute · v${Core.version}</div>`;

            UI.el('tem-n-enabled').onchange = () => {
                Core.store.set('likeMuteEnabled', UI.el('tem-n-enabled').checked);
                if (this.watching) this.scanDom();
            };
            UI.el('tem-n-autostart').onchange = () =>
                Core.store.set('likeMuteAutoStart', UI.el('tem-n-autostart').checked);
            UI.el('tem-n-start').onclick = () => this.startWatch();
            UI.el('tem-n-stop').onclick = () => this.stopWatch();
            UI.el('tem-n-scan').onclick = () => this.scanDom(true);
            UI.el('tem-n-unhide').onclick = () => this.unhideAll();
            UI.el('tem-n-save').onclick = () => {
                const list = String(UI.el('tem-n-patterns').value || '')
                    .split(/\r?\n/).map(s => s.trim()).filter(Boolean);
                Core.store.set('likeMutePatterns', list);
                this.setStatus('idle', 'Patterns saved (' + list.length + ')');
                if (this.watching) this.scanDom(true);
            };
            UI.el('tem-n-reset').onclick = () => {
                Core.store.set('likeMutePatterns', this.defaultPatterns);
                UI.el('tem-n-patterns').value = this.defaultPatterns.join('\n');
                this.setStatus('idle', 'Patterns reset');
            };

            this.refreshStats();
            this._setWatchUi(this.watching);
            if (this.watching) this.setStatus('run', 'Watching notifications…');
        },

        setStatus(kind, text) {
            const el = UI.el('tem-n-status');
            if (!el) return;
            el.className = 'tem-status ' + kind;
            el.textContent = text;
        },

        refreshStats() {
            const h = UI.el('tem-n-hidden');
            const s = UI.el('tem-n-state');
            const p = UI.el('tem-n-path');
            if (h) h.textContent = String(this.hiddenThisSession);
            if (s) s.textContent = this.watching ? 'On' : 'Off';
            if (p) {
                try {
                    const path = (location.pathname || '/').split('?')[0];
                    p.textContent = path.length > 14 ? path.slice(0, 12) + '…' : path;
                } catch (_) { p.textContent = '–'; }
            }
        },

        _setWatchUi(on) {
            const start = UI.el('tem-n-start');
            const stop = UI.el('tem-n-stop');
            if (start) start.disabled = on;
            if (stop) stop.disabled = !on;
        },

        startWatch() {
            if (this.watching) return;
            this.watching = true;
            this._setWatchUi(true);
            this.setStatus('run', 'Watching notifications…');
            this.refreshStats();
            this.scanDom(true);

            this.observer = new MutationObserver(() => this.scheduleScan());
            try {
                this.observer.observe(document.body || document.documentElement, {
                    childList: true, subtree: true
                });
            } catch (e) {
                console.warn('[TEM NotifMute] observer failed', e);
            }
        },

        stopWatch() {
            this.watching = false;
            if (this.observer) {
                try { this.observer.disconnect(); } catch (_) { }
                this.observer = null;
            }
            this._setWatchUi(false);
            this.setStatus('idle', 'Stopped');
            this.refreshStats();
        },

        scheduleScan() {
            if (this._scanScheduled) return;
            this._scanScheduled = true;
            const run = () => {
                this._scanScheduled = false;
                if (this.watching) this.scanDom(false);
            };
            if (typeof requestAnimationFrame === 'function') requestAnimationFrame(run);
            else setTimeout(run, 50);
        },

        _patterns() {
            const list = Core.store.get('likeMutePatterns', this.defaultPatterns) || this.defaultPatterns;
            return list.map(p => String(p).toLowerCase()).filter(Boolean);
        },

        /**
         * Find notification cells. X uses cellInnerDiv wrappers; fall back to articles.
         */
        _cells() {
            const primary = document.querySelectorAll('[data-testid="cellInnerDiv"]');
            if (primary.length) return primary;
            return document.querySelectorAll('article, [data-testid="notification"]');
        },

        isLikeNotification(text) {
            const t = String(text || '').toLowerCase().replace(/\s+/g, ' ');
            if (!t) return false;
            // Prefer like matches; skip pure follow/reply if they don't also say liked
            const patterns = this._patterns();
            for (let i = 0; i < patterns.length; i++) {
                if (t.indexOf(patterns[i]) !== -1) return true;
            }
            // Heuristic: “… liked your …” without needing full phrase list
            if (/\bliked your\b/.test(t)) return true;
            if (/\bliked a (post|reply|repost|retweet|quote|photo|video)\b/.test(t) && /\byou\b/.test(t)) return true;
            return false;
        },

        /**
         * @param {boolean} force  update status text even if disabled
         */
        scanDom(force) {
            this.refreshStats();
            const enabled = Core.store.get('likeMuteEnabled', true);
            if (!enabled && !force) return;

            // Only act on notifications routes (still allow manual "scan once")
            const path = (location.pathname || '').toLowerCase();
            const onNotifs = path.indexOf('/notifications') !== -1;
            if (!onNotifs && !force) {
                if (force) this.setStatus('pause', 'Open /notifications to mute likes');
                return;
            }
            if (!enabled) {
                if (force) this.setStatus('pause', 'Like-mute disabled in settings');
                return;
            }

            let newly = 0;
            const cells = this._cells();
            for (let i = 0; i < cells.length; i++) {
                const cell = cells[i];
                if (cell.getAttribute('data-tem-like-hidden') === '1') continue;
                // Prefer the notification “head” text; full cell is fine as fallback
                const text = cell.textContent || '';
                if (!this.isLikeNotification(text)) continue;

                // Don't hide if it also looks like a primary reply thread starter with only "liked" in nested UI chrome
                // (keep simple: pattern match is enough)

                cell.setAttribute('data-tem-like-hidden', '1');
                cell.style.setProperty('display', 'none', 'important');
                newly++;
                this.hiddenThisSession++;
            }
            this.refreshStats();
            if (force || newly) {
                this.setStatus(this.watching ? 'run' : 'idle',
                    newly ? ('Hid ' + newly + ' like notification(s)') : 'No new like rows');
            }
        },

        unhideAll() {
            const nodes = document.querySelectorAll('[data-tem-like-hidden="1"]');
            for (let i = 0; i < nodes.length; i++) {
                const el = nodes[i];
                el.removeAttribute('data-tem-like-hidden');
                el.style.removeProperty('display');
            }
            this.setStatus('idle', 'Unhid ' + nodes.length + ' row(s)');
        }
    };

/* ---- src/modules/about.js ---- */
/**
 * @module about
 * @see docs/modules/about.md
 */
    const About = {
        render() {
            UI.el('tem-pane-about').innerHTML = `
              <div class="tem-section">
                <h4>Twitter Experience Manager</h4>
                <p>A modular usability toolkit for X.com — same packaging style as Tweepcred Manager (console paste + Greasemonkey), focused on network hygiene and timeline control.</p>
                <ul>
                  <li><strong>Followers</strong> — snapshot who follows you; sort Following by each account's following count.</li>
                  <li><strong>Geo Guard</strong> — <strong>soft-hide</strong> (and optionally block) timeline posts by region needles (defaults: India + South Asia).</li>
                  <li><strong>Notifs</strong> — hide “liked your post” rows on the notifications page (client-side).</li>
                </ul>
              </div>
              <div class="tem-section">
                <h4>Install (Violentmonkey)</h4>
                <p>Open <code>dist/twitter-experience-manager.user.js</code> in Violentmonkey (or use “Install from URL” with the raw GitHub file). Metadata uses <code>@grant none</code>, <code>@inject-into page</code>, <code>@run-at document-idle</code>, <code>@noframes</code> — same bundle works as a console paste.</p>
              </div>
              <div class="tem-section">
                <h4>Modular source</h4>
                <p>Each feature is a file under <code>src/modules/</code> with docs in <code>docs/modules/</code>. Rebuild: <code>node scripts/build.js</code>.</p>
              </div>
              <div class="tem-section">
                <h4>Related</h4>
                <p>Reputation tooling lives in <strong>Tweepcred Manager</strong>. This project reuses the Followers tracker concept and shared dual-mode architecture.</p>
              </div>
              <div class="tem-warn-box">Automating X violates its Terms of Service. Region filters use self-reported text only. Prefer soft-hide over live block. At your own risk.</div>
              <div class="tem-foot">Twitter Experience Manager v${Core.version}</div>`;
        }
    };

/* ---- src/boot.js ---- */
/**
 * @module boot
 * @see docs/modules/bootstrap.md
 */
    function temBoot() {
        if (!document.body && !document.documentElement) {
            setTimeout(temBoot, 50);
            return;
        }
        Core.init();
        UI.build();
        Followers.render();
        Followers.firstShow = false;
        GeoGuard.render();
        GeoGuard.firstShow = false;
        NotifMute.render();
        NotifMute.firstShow = false;
        About.render();
        UI.switchTab('followers');

        // Auto-start modules (persisted prefs). Defer so X's SPA shell settles.
        setTimeout(function () {
            try {
                if (Core.store.get('geoAutoStart', false)) GeoGuard.startWatch();
            } catch (_) { }
            try {
                if (Core.store.get('likeMuteAutoStart', true)) NotifMute.startWatch();
            } catch (_) { }
        }, 1200);

        console.log(
            '%c✦ Twitter Experience Manager v' + Core.version + ' ready. @' + (Core.username || '?') +
            ' (Violentmonkey / Tampermonkey / console)',
            'color:#7856ff;font-weight:bold;font-size:14px'
        );
    }

    temBoot();

